import 'package:flutter/material.dart';

void main() => runApp(const MyApp());

class MyApp extends StatelessWidget {
  const MyApp({super.key});

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      debugShowCheckedModeBanner: false,
      home: GridTela(),
    );
  }
}

class GridTela extends StatelessWidget {
  final List<Map<String, String>> locais = [
    {'title': 'Chennai Flower Market', 'url': 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSDziUXRiXcEXtkD-4IhhTuhAJdyXhHv9nLiQ&s'}, // [cite: 3]
    {'title': 'Tanjore Bronze Works', 'url': 'data:image/jpeg;base64,'},  // [cite: 4]
    {'title': 'Tanjore Market', 'url': 'data:image/jpeg;base64,'},        // [cite: 5]
    {'title': 'Tanjore Thanjavur Temple', 'url': 'data:image/jpeg;base64,'}, // [cite: 6]
    {'title': 'Tanjore Thanjavur Temple', 'url': 'data:image/jpeg;base64,'}, // [cite: 7]
    {'title': 'Pondicherry Salt Farm', 'url': 'data:image/jpeg;base64,'},    // [cite: 8, 9]
  ];

  GridTela({super.key});

  @override
  Widget build(BuildContext context) {
    return Scaffold(
   
      body: GridView.builder(
        padding: const EdgeInsets.all(10),
        gridDelegate: const SliverGridDelegateWithFixedCrossAxisCount(
          crossAxisCount: 2,
          crossAxisSpacing: 10,
          mainAxisSpacing: 10,
        ),
        itemCount: locais.length,
        itemBuilder: (context, index) {
          return ClipRRect(
            borderRadius: BorderRadius.circular(10), // Bordas arredondadas
            child: Stack(
              children: [
                // 1. A Imagem ocupando todo o espaço
                Positioned.fill(
                  child: Image.network(
                    locais[index]['url']!,
                    fit: BoxFit.cover,
                  ),
                ),
              
                Positioned(
                  bottom: 0,
                  left: 0,
                  right: 0,
                  child: Container(
                    color: Colors.black.withOpacity(0.6), 
                    padding: const EdgeInsets.all(8.0),
                    child: Text(
                      locais[index]['title']!,
                      style: const TextStyle(
                        color: Colors.white,
                        fontWeight: FontWeight.bold,
                      ),
                      textAlign: TextAlign.center,
                    ),
                  ),
                ),
              ],
            ),
          );
        },
      ),
    );
  }
}